// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MOD 1000000007

// Function to find the prime factorization of a number
void primeFactorization(int n, int *factors, int *powers) {
    int i, j;
    for (i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            factors[i]++;
            powers[i] = 1;
            while (n % i == 0) {
                n /= i;
                factors[i]++;
            }
        }
    }
    if (n > 1) {
        factors[n]++;
        powers[n] = 1;
    }
}

// Function to find the GCD of two numbers
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

// Function to find the LCM of two numbers
int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int N;
    scanf("%d", &N);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int factors[1000001] = {0};
    int powers[1000001] = {0};
    for (int i = 0; i < N; i++) {
        primeFactorization(A[i], factors, powers);
    }
    int GCD = 1;
    for (int i = 2; i <= 1000000; i++) {
        if (factors[i] > 0) {
            GCD *= pow(i, factors[i] / N);
        }
    }
    if (GCD == 1) {
        printf("justdoit\n");
    } else {
        int LCM = 1;
        for (int i = 2; i <= 1000000; i++) {
            if (factors[i] > 0) {
                LCM *= pow(i, (factors[i] + N - 1) / N);
            }
        }
        printf("%d\n", LCM % MOD);
    }
    return 0;
}

